    def lock_into_grid(self, grid: List[List[Cell]]):
        for x, y in self.get_cells():
            if 0 <= x < GRID_WIDTH and 0 <= y < GRID_HEIGHT:
                grid[y][x].state = CellState.GEM
                grid[y][x].color = self.color

def clear_falling(grid: List[List[Cell]]):
    for row in grid:
        for cell in row:
            if cell.state == CellState.FALLING:
                cell.reset()

class GameState:
    def __init__(self):
        self.grid = create_grid()
        self.current_tetromino = None
        self.next_tetromino = self._new_tetromino()
        self.score = 0
        self.game_over = False
        self.spawn_tetromino()

    def _new_tetromino(self) -> Tetromino:
        return Tetromino(random.choice(list(TETROMINO_SHAPES.keys())))

    def spawn_tetromino(self) -> bool:
        clear_falling(self.grid)
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self._new_tetromino()
        self.current_tetromino.x = GRID_WIDTH // 2 - 2
        self.current_tetromino.y = 0
        if self.current_tetromino.collides(self.grid):
            self.game_over = True
            return False
        self.current_tetromino.place_on_grid(self.grid)
        return True

    def move_tetromino_down(self) -> bool:
        if not self.current_tetromino.collides(self.grid, dy=1):
            self.current_tetromino.clear_from_grid(self.grid)
            self.current_tetromino.y += 1
            self.current_tetromino.place_on_grid(self.grid)
            return True
        return False

    def move_tetromino_sideways(self, dx: int):
        if not self.current_tetromino.collides(self.grid, dx=dx):
            self.current_tetromino.clear_from_grid(self.grid)
            self.current_tetromino.x += dx
            self.current_tetromino.place_on_grid(self.grid)

    def rotate_tetromino(self):
        original = [row[:] for row in self.current_tetromino.matrix]
        self.current_tetromino.clear_from_grid(self.grid)
        self.current_tetromino.rotate()
        if self.current_tetromino.collides(self.grid):
            self.current_tetromino.matrix = original
        self.current_tetromino.place_on_grid(self.grid)

    def hard_drop(self):
        while self.move_tetromino_down():
            pass

    def lock_and_spawn(self):
        self.current_tetromino.lock_into_grid(self.grid)
        self.spawn_tetromino()

    def tick(self):
        clear_falling(self.grid)
        if not self.move_tetromino_down():
            self.lock_and_spawn()
            self.clear_lines_and_matches()
            if self.game_over:
                return
        else:
            self.current_tetromino.place_on_grid(self.grid)

    def get_grid_copy(self) -> List[List[Cell]]:
        return [[Cell(cell.state, cell.color) for cell in row] for row in self.grid]

    def apply_gravity(self):
        """Collapse all gems downward in each column."""
        for x in range(GRID_WIDTH):
            stack = []
            for y in range(GRID_HEIGHT):
                if self.grid[y][x].is_gem():
                    stack.append(self.grid[y][x].color)
            for y in range(GRID_HEIGHT - 1, -1, -1):
                if stack:
                    color = stack.pop()
                    self.grid[y][x].state = CellState.GEM
                    self.grid[y][x].color = color
                else:
                    self.grid[y][x].reset()

    def clear_lines_and_matches(self):
        """
        Detects and clears full lines and 3+ gem matches,
        applies gravity, then recurses until stable.
        """
        total_lines = self.clear_lines()
        total_matches = self.clear_matches()
        if total_lines > 0 or total_matches > 0:
            # Award points
            self.score += total_lines * 100
            self.score += total_matches * 50
            # Gems and empty cells settle
            self.apply_gravity()
            # Recurse for chain reactions
            self.clear_lines_and_matches()

    def clear_lines(self) -> int:
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(not self.grid[y][x].is_empty() for x in range(GRID_WIDTH)):
                for x in range(GRID_WIDTH):
                    self.grid[y][x].reset()
                for yy in range(y, 0, -1):
                    for x in range(GRID_WIDTH):
                        self.grid[yy][x].state = self.grid[yy-1][x].state
                        self.grid[yy][x].color = self.grid[yy-1][x].color
                for x in range(GRID_WIDTH):
                    self.grid[0][x].reset()
                lines_cleared += 1
        return lines_cleared

    def clear_matches(self) -> int:
        matches = self.find_matches()
        for x, y in matches:
            self.grid[y][x].reset()
        return len(matches)

    def find_matches(self) -> List[Tuple[int, int]]:
        matches = set()
        # Horizontal
        for y in range(GRID_HEIGHT):
            x = 0
            while x < GRID_WIDTH - 2:
                if self.grid[y][x].is_gem():
                    color = self.grid[y][x].color
                    length = 1
                    while x + length < GRID_WIDTH and self.grid[y][x+length].is_gem() and self.grid[y][x+length].color == color:
                        length += 1
                    if length >= 3:
                        for i in range(length):
                            matches.add((x+i, y))
                    x += length
                else:
                    x += 1
        # Vertical
        for x in range(GRID_WIDTH):
            y = 0
            while y < GRID_HEIGHT - 2:
                if self.grid[y][x].is_gem():
                    color = self.grid[y][x].color
                    length = 1
                    while y + length < GRID_HEIGHT and self.grid[y+length][x].is_gem() and self.grid[y+length][x].color == color:
                        length += 1
                    if length >= 3:
                        for i in range(length):
                            matches.add((x, y+i))
                    y += length
                else:
                    y += 1
        return list(matches)
